import{_ as n,C as o,o as s,c as l,E as a,w as t,a as r,a0 as g}from"./chunks/framework.CkNTPv-z.js";const P=JSON.parse('{"title":"Portugal Legal Rights","description":"Legal rights for transgender people in Portugal","frontmatter":{"layout":"doc","title":"Portugal Legal Rights","description":"Legal rights for transgender people in Portugal"},"headers":[],"relativePath":"europe/portugal/legal-rights.md","filePath":"europe/portugal/legal-rights.md","lastUpdated":null}'),d={name:"europe/portugal/legal-rights.md"};function c(h,e,p,u,m,f){const i=o("Badge");return s(),l("div",null,[a(i,{variant:"yellow"},{default:t(()=>[...e[0]||(e[0]=[r("Self-ID since 2018",-1)])]),_:1}),a(i,{variant:"green"},{default:t(()=>[...e[1]||(e[1]=[r("Anti-Discrimination Laws",-1)])]),_:1}),e[2]||(e[2]=g('<h1 id="legal-rights-in-portugal" tabindex="-1">Legal Rights in Portugal <a class="header-anchor" href="#legal-rights-in-portugal" aria-label="Permalink to &quot;Legal Rights in Portugal&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Portugal adopted a self-determination model for legal gender recognition through <strong>Law 38/2018</strong> (Gender Identity Law), passed in July 2018. The law allows individuals aged 18 and over to change their legal gender and name on official documents through a simple administrative process.</p><p>The process:</p><ul><li>Application at the <strong>Civil Registry Office (Conservatória do Registo Civil)</strong></li><li>No medical reports, surgery, or psychological assessments required</li><li>No requirement for divorce or marital status change</li><li>Completed within approximately 30-60 days</li><li>For minors aged 16-18, parental consent required</li><li>Minors under 16 require judicial authorisation</li></ul><p>The law explicitly prohibits any requirement for sterilisation, medical treatment, or diagnosis.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>Name changes are processed as part of the gender recognition application at the Civil Registry Office. A new first name consistent with the affirmed gender can be chosen. For name changes without gender marker change, a separate administrative process exists through the <strong>Institute of Registries and Notaries (IRN)</strong>.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Portugal prohibits discrimination based on gender identity and sexual orientation:</p><ul><li><strong>Constitutional protection</strong> — Article 13 of the Portuguese Constitution prohibits discrimination</li><li><strong>Labour Code</strong> — Prohibits discrimination in employment</li><li><strong>Law 38/2018</strong> — Explicitly prohibits discrimination against transgender people</li><li><strong>Conversion therapy</strong> — Banned in 2023</li><li><strong>Healthcare</strong> — Right to access gender affirming care without discrimination</li><li><strong>Education</strong> — Protection in schools</li><li><strong>Housing</strong> — Anti-discrimination in rental and purchase</li></ul><p>The <strong>Commission for Equality and Against Racial Discrimination (CICDR)</strong> handles complaints.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Portugal&#39;s Penal Code includes sexual orientation and gender identity as aggravating circumstances for crimes. The law provides for enhanced penalties when crimes are motivated by hatred or prejudice. This covers:</p><ul><li>Physical violence and assault</li><li>Threats and intimidation</li><li>Property damage</li><li>Hate speech</li></ul><p>However, enforcement and reporting mechanisms are still developing compared to Nordic countries.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>ILGA Portugal</strong> — <a href="https://www.ilga-portugal.pt/" target="_blank" rel="noreferrer">ilga-portugal.pt</a></li><li><strong>Portugal Government - Portal do Cidadão</strong> — <a href="https://www.portaldocidadao.pt/" target="_blank" rel="noreferrer">portaldocidadao.pt</a></li><li><strong>IRN - Registries and Notaries</strong> — <a href="https://www.irn.mj.pt/" target="_blank" rel="noreferrer">irn.mj.pt</a></li><li><strong>CICDR - Anti-Discrimination Commission</strong> — <a href="https://www.cicdr.pt/" target="_blank" rel="noreferrer">cicdr.pt</a></li><li><strong>rede ex aequo</strong> — LGBTQ+ youth organisation: <a href="https://www.redeexaequo.pt/" target="_blank" rel="noreferrer">redeexaequo.pt</a></li></ul>',18))])}const b=n(d,[["render",c]]);export{P as __pageData,b as default};
